import DOM_SELECTORS from "../selectors/registerTransactionSelectorsMap";
import useForm from "../components/useForm";
import useToggleDisplay from "../utils/useToggleDisplay";

const registerTransactionController = () => {
    const {
        PRZELEWY24_ORDER_CONFIRMATION_ALERTS,
        PRZELEWY24_ORDER_CONFIRMATION_INPUT,
    } = DOM_SELECTORS;

    const {
        registerTransaction,
    } = useForm();

    const {
        show,
        hide,
        toggle,
    } = useToggleDisplay();

    const toggleAlerts = (alert) => {
        Object.keys(PRZELEWY24_ORDER_CONFIRMATION_ALERTS).forEach((key) => {
            const element = document.querySelector(PRZELEWY24_ORDER_CONFIRMATION_ALERTS[key]);

            if (key === alert) {
                show(element);
            } else {
                hide(element);
            }
        });
    }

    const switchAlerts = (status) => {
        switch (status) {
            case 'success':
                toggleAlerts('SUCCESS');
                break;
            case 'pending':
                toggleAlerts('WARNING_REPAYMENT');
                break;
            case 'error':
                toggleAlerts('ERROR');
                break;
            case 'long_term_payment':
                toggleAlerts('LONG_TERM');
                break;
            case 'order_cancelled':
                toggleAlerts('CANCELLED');
                break;
            case 'already_payed':
                toggleAlerts('ALREADY_PAYED');
                break;
            default:
                toggleAlerts('WARNING');
        }
    }

    const registerTransactionFetch = async (url) => await registerTransaction(url, 1, 5000);

    const initRegisterTransaction = () => {
        const input = document.querySelector(PRZELEWY24_ORDER_CONFIRMATION_INPUT);

        if (!input) {
            return;
        }

        const url = input.dataset.url;
        const completed = input.value;

        if (completed) {
            setTimeout(() => {
                switchAlerts('success');
            }, 1000);
            return;
        }

        if (!url) {
            toggleAlerts('WARNING');
            return;
        }

        registerTransactionFetch(url).then((response) => {
            if (!response || !response.status || !response.completed) {
                toggleAlerts('WARNING');
                return;
            }

            switchAlerts(response.status);
        });
    }

    const init = () => {
        initRegisterTransaction();
    }

    return {
        init
    }
}

export default registerTransactionController;
